// ============================================================
// Parse Twilio Input - FIXED (English)
// ============================================================

let incoming = {};
try {
  incoming = $('Twilio Webhook').first().json;
} catch(e) {}

const body = incoming.body || {};

const speechResult =
  body.SpeechResult ?? incoming.SpeechResult ?? body.speechResult ?? incoming.speechResult ?? "";

const callSid =
  body.CallSid ?? incoming.CallSid ?? body.callSid ?? incoming.callSid ?? "test_call";

const from =
  body.From ?? incoming.From ?? body.from ?? incoming.from ?? "test_phone";

const staticData = $getWorkflowStaticData("global");

if (!staticData.conversations) {
  staticData.conversations = {};
}

if (!staticData.conversations[callSid]) {
  staticData.conversations[callSid] = {
    messages: [],
    reservationState: { collecting: false, name: null, phone: null, date: null, time: null, guests: null, completed: false },
    orderState: { collecting: false, name: null, address: null, order: null, phone: null, completed: false },
    callerPhone: from,
    createdAt: new Date().toISOString()
  };
}

const conversation = staticData.conversations[callSid];
const userInput = (speechResult || "").trim();

if (userInput !== "") {
  conversation.messages.push({ role: "user", content: userInput });
}

// FIXED: added fallback so undefined systemPrompt never breaks OpenAI call
let systemPrompt = "You are a restaurant assistant. Reply in English.";
try {
  const sp = $("Universal System Prompt").first().json.systemPrompt;
  if (sp) systemPrompt = sp;
} catch(e) {}

const limitedMessages = conversation.messages.slice(-24);

const memoryInstruction = [
  'CALL CONTEXT:',
  'Caller phone from Twilio: ' + from,
  'If the customer does not provide another phone number, use this caller phone for orders/reservations.',
  'Review all previous user messages before asking for missing details.',
  'If name, address, order, and phone are known, output ORDER_COMPLETE now.'
].join('\n');

const messagesForOpenAI = [
  { role: "system", content: systemPrompt },
  { role: "system", content: memoryInstruction },
  ...limitedMessages
];

// Cleanup old conversations (keep latest 30)
const keys = Object.keys(staticData.conversations);
if (keys.length > 30) {
  keys.slice(0, keys.length - 30).forEach(k => delete staticData.conversations[k]);
}

// FIXED: added fallback for restaurantId
let restaurantId = "";
try {
  const rid = $("Restaurant Config").first().json.restaurantId;
  if (rid) restaurantId = rid;
} catch(e) {}

return [{
  json: {
    callSid,
    from,
    speechResult: userInput,
    messages: messagesForOpenAI,
    reservationState: conversation.reservationState,
    orderState: conversation.orderState,
    restaurantId
  }
}];

// ============================================================
// Process AI Response - FIXED (English)
// ============================================================

const openAiResponse = $input.first().json;
const prevData = $('Parse Twilio Input').first().json;
const callSid = prevData.callSid || 'call_' + new Date().getTime();
const from = prevData.from;
const restaurantId = prevData.restaurantId;

// FIXED: check for OpenAI error first, then extract message
let aiMessage = '';

try {
  // Check for API-level error
  if (openAiResponse.error) {
    aiMessage = "Sorry, the service is currently unavailable. Please try again.";
  }
  // Standard chat completions format
  else if (
    openAiResponse.choices &&
    openAiResponse.choices[0] &&
    openAiResponse.choices[0].message
  ) {
    aiMessage = openAiResponse.choices[0].message.content || '';
  }
  // Responses API format (fallback)
  else if (
    openAiResponse.output &&
    openAiResponse.output[0] &&
    openAiResponse.output[0].content &&
    openAiResponse.output[0].content[0]
  ) {
    aiMessage = openAiResponse.output[0].content[0].text || '';
  }
  else if (openAiResponse.message && openAiResponse.message.content) {
    aiMessage = openAiResponse.message.content;
  }
  else if (typeof openAiResponse.content === 'string') {
    aiMessage = openAiResponse.content;
  }
  else {
    aiMessage = "Yes, please tell me, how can I help you?";
  }
} catch(e) {
  aiMessage = "Yes, please tell me, how can I help you?";
}

// Conversation memory
const staticData = $getWorkflowStaticData('global');
if (!staticData.conversations) staticData.conversations = {};
if (!staticData.conversations[callSid]) {
  staticData.conversations[callSid] = {
    messages: [],
    reservationState: { collecting: false, name: null, phone: null, date: null, time: null, guests: null, completed: false },
    orderState: { collecting: false, name: null, address: null, order: null, phone: null, completed: false },
    callerPhone: from,
    createdAt: new Date().toISOString()
  };
}

staticData.conversations[callSid].messages.push({ role: 'assistant', content: aiMessage });

// Detect markers with flexible regex
const reservationMatch = aiMessage.match(/RESERVATION_COMPLETE:\s*({[\s\S]*?})/i);
const orderMatch = aiMessage.match(/ORDER_COMPLETE:\s*({[\s\S]*?})/i);

let reservationData = null;
let orderData = null;
let spokenMessage = aiMessage;

if (reservationMatch) {
  try {
    reservationData = JSON.parse(reservationMatch[1]);
    spokenMessage = spokenMessage.replace(/RESERVATION_COMPLETE:\s*{[\s\S]*?}/i, '').replace(/\n+/g, ' ').trim();
    staticData.conversations[callSid].reservationState = {
      ...staticData.conversations[callSid].reservationState,
      ...reservationData,
      completed: true,
      collecting: false
    };
  } catch(e) { reservationData = null; }
}

if (orderMatch) {
  try {
    orderData = JSON.parse(orderMatch[1]);
    spokenMessage = spokenMessage.replace(/ORDER_COMPLETE:\s*{[\s\S]*?}/i, '').replace(/\n+/g, ' ').trim();
    staticData.conversations[callSid].orderState = {
      ...staticData.conversations[callSid].orderState,
      ...orderData,
      completed: true,
      collecting: false
    };
  } catch(e) { orderData = null; }
}

// Clean for TwiML speech
spokenMessage = spokenMessage
  .replace(/&/g, 'and')
  .replace(/</g, '')
  .replace(/>/g, '')
  .replace(/"/g, '')
  .replace(/'/g, '')
  .replace(/[{}\[\]]/g, '')
  .trim();

if (!spokenMessage || spokenMessage.length < 3) {
  spokenMessage = "Yes, please tell me, how can I help you?";
}

return [{
  json: {
    restaurantId,
    callSid,
    from,
    aiMessage: spokenMessage,
    rawAiMessage: aiMessage,
    reservationData,
    orderData,
    shouldSaveReservation: reservationData !== null,
    shouldSaveOrder: orderData !== null,
    timestamp: new Date().toISOString()
  }
}];

// Build TwiML (Normal Response) - Dynamic Xorvian
let restaurant, data, aiMessage, webhook;
try { restaurant = $('Restaurant Config').first().json.restaurant; } catch(e) { restaurant = {}; }
try { data = $('Process AI Response').first().json; } catch(e) { data = {}; }
aiMessage = (data.aiMessage || restaurant.gatherMessage || 'Yes, please tell me, how can I help you?').trim();
webhook = (restaurant.webhookPath || '7d1e2d95-94bc-4f30-8b40-39a01a8415ca');
const safeMessage = aiMessage.replace(/&/g, 'and').replace(/</g, '').replace(/>/g, '').replace(/\"/g, '').replace(/'/g, '');
let host = 'officer3765.app.n8n.cloud';
let proto = 'https';
try {
  const incomingHeaders = $('Twilio Webhook').first().json.headers || {};
  host = incomingHeaders['x-forwarded-host'] || incomingHeaders['host'] || host;
  let protoHeader = incomingHeaders['x-forwarded-proto'] || proto;
  if (protoHeader.includes(',')) protoHeader = protoHeader.split(',')[0].trim();
  proto = protoHeader;
} catch(e) {}
const baseUrl = proto + '://' + host;
let audioUrl = '';
try { audioUrl = $('Upload an asset from file data').first().json.secure_url || $('Upload an asset from file data').first().json.url || ''; } catch(e) {}
const promptXml = audioUrl ? '<Play>' + audioUrl + '</Play>' : '<Say>' + safeMessage + '</Say>';
const language = $('Restaurant Config').first().json.settings?.twilioLanguage || 'en-US';
const twiml = '<?xml version="1.0" encoding="UTF-8"?>\n' +
'<Response>\n' +
'<Gather\n' +
'  input="speech"\n' +
'  action="' + baseUrl + '/webhook/' + webhook + '"\n' +
'  method="POST"\n' +
'  language="' + language + '"\n' +
'  speechTimeout="auto"\n' +
'  timeout="5"\n' +
'  actionOnEmptyResult="true">\n' +
promptXml + '\n' +
'</Gather>\n' +
'<Say>I could not hear your voice, please say it again.</Say>\n' +
'<Redirect method="POST">' + baseUrl + '/webhook/' + webhook + '</Redirect>\n' +
'</Response>';
return [{ json: { twiml } }];

const menu =
$('Restaurant Menu')
.first()
.json
.menu;

let formatted='';

for(const category of menu.categories){

formatted+=category.name.toUpperCase();

formatted+='\n';

for(const item of category.items){

formatted+='- '+item.name;

if(item.price){

formatted+=' : Rs.'+item.price;

}

if(item.sizes){

formatted+=' (';

const sizes=[];

for(const key in item.sizes){

sizes.push(
key+
' Rs.'+
item.sizes[key]
);

}

formatted+=sizes.join(', ');

formatted+=')';

}

formatted+='\n';

}

formatted+='\n';

}

return[{

json:{

formattedMenu:formatted

}

}];
